final:
module RefModule(  
    input wire D,  
    input wire WL,  
    input wire clk,  
    output reg Q  
);  
    reg obf_stored_data;  
    always @(posedge clk) begin  
        if (WL) begin  
            obf_stored_data <= D;  
        end  
        Q <= obf_stored_data;  
    end  
endmodule
